// // This module decodes a 2-bit input into a 4-bit output, but it does so in reverse order and without considering the enable signal.
module decoder_2to4(A, enable, Y);
    input [1:0] A;
    input enable;
    output [3:0] Y;
    reg [3:0] Y;

    always @(*) begin
        if (enable) begin
            case (A)
                2'b00: Y = 4'b0001;
                2'b01: Y = 4'b0010;
                2'b10: Y = 4'b0100;
                2'b11: Y = 4'b1000;
                default: Y = 4'b0000;
            endcase
        end
        else begin
            Y = 4'b0000;
        end
    end
endmodule
